void NativeMobileCore::registerModule(jsi::Runtime &rt, std::shared_ptr<react::CallInvoker> callInvoker) {
    auto invoker = std::make_shared<uniffi_runtime::UniffiCallInvoker>(callInvoker);
    auto tm = std::make_shared<NativeMobileCore>(rt, invoker);
    auto obj = rt.global().createFromHostObject(rt, tm);
    rt.global().setProperty(rt, "NativeMobileCore", obj);
}

void NativeMobileCore::unregisterModule(jsi::Runtime &rt) {
    uniffi::mobile_core::registry::clearRegistry();
}

